definition.script:
pipeline {
    agent any

    stages {
        stage('Checkout') {
            steps {
                // Ganti dengan URL Repo GitHub lo yang tadi
                git 'https://github.com/bym-1091/latihan-devops.git'
            }
        }

        stage('SonarQube Scan') {
            steps {
                script {
                    // Kita jalanin perintah scanner yang lo coba tadi lewat docker
                    sh """
                    docker run --rm --network=host \
                    -v "\$(pwd):/usr/src" \
                    sonarsource/sonar-scanner-cli \
                    -Dsonar.projectKey=test \
                    -Dsonar.sources=. \
                    -Dsonar.host.url=http://localhost:9000 \
                    -Dsonar.token=sqp_d884963ebfd2e32bbdbf633393330cf3c9772794
                    """
                }
            }
        }

        stage('Build Image') {
            steps {
                // Kita tambahin ls -la biar kita bisa liat di log, Jenkins sebenernya dapet file apa aja
                sh 'ls -la'

                // Kita paksa pake -f buat nunjuk file secara spesifik
                // Kalau di folder lo namanya 'dockerfile', ganti jadi -f dockerfile
                // Kalau namanya 'Dockerfile', ganti jadi -f Dockerfile
                sh 'docker build -t image-materi-jenkins -f dockerfile .'
            }
        }
    }
}
